import React from "react";

const toF = (c) => (c == null ? null : (c * 9) / 5 + 32);

// Precip formatter: show mm for metric, inches for imperial
function fmtPrecip(mm, unit) {
  if (mm == null || Number.isNaN(Number(mm))) return "—";
  const n = Number(mm);
  if (unit === "imperial") {
    const inches = n / 25.4;
    return `${inches.toFixed(inches >= 1 ? 2 : 2)} in`;
  }
  return `${n.toFixed(n >= 1 ? 1 : 1)} mm`;
}

export default function HourlyItem({
  label,        // time label "3 PM"
  temp,         // Celsius (number)
  pop,          // % 0..100 (already normalized by parent; can be null)
  icon,         // icon code like "10d"
  desc,         // human label
  precip = 0,   // mm
  unit = "metric",
  iconSrc,      // full URL (pre-built in parent)
}) {
  const displayTemp = unit === "imperial"
    ? Math.round(toF(temp))
    : Math.round(temp);

  return (
    <div className="snap-start shrink-0 w-24 bg-black/35 backdrop-blur-md border border-white/10 rounded-xl shadow-md py-3 px-2 text-center">
      <div className="text-[11px] text-white/70 font-medium">{label}</div>

      <img
        src={iconSrc}
        alt={typeof desc === "string" ? desc : "weather"}
        className="w-10 h-10 mx-auto my-1 drop-shadow-[0_6px_22px_rgba(128,90,213,0.35)]"
        loading="lazy"
      />

      <div className="text-white text-base font-semibold">{Number.isFinite(displayTemp) ? `${displayTemp}°` : "—"}</div>

      <div className="text-[11px] text-white/60 mt-1 truncate capitalize">
        {typeof desc === "string" ? desc : String(desc || "")}
      </div>

      <div className="text-[11px] text-white/60 mt-1">
        {pop != null ? `${pop}%` : "—"} • {fmtPrecip(precip, unit)}
      </div>
    </div>
  );
}
